.load extensions/dicom/target/wasm32-wasip2/release/dicom_extension.component.wasm

/* DICOM medical-imaging metadata extraction.
 *
 * Fixtures (all hex literals):
 *
 *   dicom_full: a hand-crafted DICOM Part 10 blob built by the
 *     parser-spec script. 128-byte 0x00 preamble + "DICM" + FMI
 *     (Explicit VR LE) carrying TransferSyntaxUID=1.2.840.10008.1.2.1
 *     + dataset with:
 *       (0008,0020) StudyDate    DA "20240115"
 *       (0008,0060) Modality     CS "CT"
 *       (0008,0070) Manufacturer LO "Acme Medical"
 *       (0010,0010) PatientName  PN "Doe^John"
 *       (0010,0020) PatientID    LO "P12345"
 *       (0028,0010) Rows         US 512
 *       (0028,0011) Columns      US 256
 *       (0028,0100) BitsAllocated US 16
 *
 *   not_dicom: 16 bytes of 0xAA  no DICM magic; every accessor
 *     must return NULL, dicom_is_valid must return 0.
 */

------------------------------------------------------------------
-- Acceptance 1: patient name (caret-delimited PN -> space-joined)
------------------------------------------------------------------
SELECT dicom_patient_name(x'');

------------------------------------------------------------------
-- Acceptance 2: patient id (LO)
------------------------------------------------------------------
SELECT dicom_patient_id(x'');

------------------------------------------------------------------
-- Acceptance 3: study date (DA "20240115" -> ISO "2024-01-15")
------------------------------------------------------------------
SELECT dicom_study_date(x'');

------------------------------------------------------------------
-- Acceptance 4: modality (CS)
------------------------------------------------------------------
SELECT dicom_modality(x'');

------------------------------------------------------------------
-- Acceptance 5: manufacturer (LO)
------------------------------------------------------------------
SELECT dicom_manufacturer(x'');

------------------------------------------------------------------
-- Acceptance 6: dimensions JSON (rows/cols/bits)
------------------------------------------------------------------
SELECT dicom_dimensions(x'');
-- spot-check the dimensions JSON via json_extract
SELECT json_extract(dicom_dimensions(x''), '$.rows');
SELECT json_extract(dicom_dimensions(x''), '$.cols');
SELECT json_extract(dicom_dimensions(x''), '$.bits');

------------------------------------------------------------------
-- Acceptance 7: transfer syntax UID
------------------------------------------------------------------
SELECT dicom_transfer_syntax(x'');

------------------------------------------------------------------
-- Acceptance 8: arbitrary tag (3-arg form). Pull StudyDate via
-- (0008, 0020); ts UID via (0002, 0010) from the FMI group.
------------------------------------------------------------------
SELECT dicom_tag(x'', '0008', '0020');
SELECT dicom_tag(x'', '0002', '0010');
-- bogus tag -> NULL
SELECT dicom_tag(x'', 'FFFF', 'FFFF');

------------------------------------------------------------------
-- Acceptance 9: metadata JSON; spot-check via json_extract
------------------------------------------------------------------
SELECT json_extract(dicom_metadata(x''), '$.modality');
SELECT json_extract(dicom_metadata(x''), '$.study_date');

------------------------------------------------------------------
-- Acceptance 10: is_valid -> 1 for full blob
------------------------------------------------------------------
SELECT dicom_is_valid(x'');

------------------------------------------------------------------
-- Acceptance 11: non-DICOM blob -> NULL on accessors; 0 on is_valid
------------------------------------------------------------------
SELECT dicom_patient_name(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT dicom_modality(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT dicom_transfer_syntax(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT dicom_metadata(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT dicom_is_valid(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');

------------------------------------------------------------------
-- Acceptance 12: NULL input -> NULL on every fn (including is_valid)
------------------------------------------------------------------
SELECT dicom_patient_name(NULL);
SELECT dicom_modality(NULL);
SELECT dicom_is_valid(NULL);

------------------------------------------------------------------
-- Acceptance 13: version is non-empty TEXT
------------------------------------------------------------------
SELECT length(dicom_version()) > 0;
